def get_personality_content(mbti: str, hd_type: Optional[str], sub_goal: Optional[str] = None) -> dict:
    """Return behavioral descriptions and dialogue scenario for the given combination.

    When sub_goal is provided, returns sub-goal-specific situational content from the
    subgoal modules instead of the general MBTI/HD descriptions.
    """
    cat = MBTI_CATEGORY.get(mbti.upper(), "NT")

    if sub_goal:
        mbti_data = MBTI_SUBGOAL.get((cat, sub_goal), {})
        hd_ctx    = HD_SUBGOAL.get((hd_type, sub_goal), "") if hd_type else ""
        return {
            "mbti_description":    mbti_data.get("mbti_context", ""),
            "hd_description":      hd_ctx,
            "tension":             mbti_data.get("tension", ""),
            "conflict_situation":  "",
            "conflict_example":    mbti_data.get("conflict_example", ""),
            "why_fails":           mbti_data.get("why_fails", ""),
            "recommended_example": mbti_data.get("recommended_example", ""),
            "the_shift":           mbti_data.get("the_shift", ""),
        }

    # General (no sub-goal): use long MBTI/HD descriptions + generic dialogue scenario
    mbti_desc = MBTI_DESCRIPTIONS.get(mbti.upper(), "")
    hd_desc   = HD_DESCRIPTIONS.get(hd_type, "") if hd_type else ""
    scenario  = DIALOGUE_SCENARIOS.get((cat, hd_type), {}) if hd_type else {}

    return {
        "mbti_description":    mbti_desc,
        "hd_description":      hd_desc,
        "tension":             scenario.get("tension", ""),
        "conflict_situation":  scenario.get("conflict_situation", ""),
        "conflict_example":    scenario.get("conflict_example", ""),
        "why_fails":           scenario.get("why_fails", ""),
        "recommended_example": scenario.get("recommended_example", ""),
        "the_shift":           scenario.get("the_shift", ""),
    }
